import React, { useState } from 'react';
import { formatDate } from '../../data/bookingData.js';
import styles from '../../styles/admin/BookingsTable.module.css';

const STATUS_COLORS = {
  confirmed: styles.statusConfirmed,
  cancelled: styles.statusCancelled,
  pending: styles.statusPending,
};

const BookingsTable = ({ bookings, onTogglePaid, onCancelBooking }) => {
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [expandedId, setExpandedId] = useState(null);

  const filtered = bookings.filter((b) => {
    const matchFilter =
      filter === 'all' ||
      (filter === 'paid' && b.paid) ||
      (filter === 'unpaid' && !b.paid) ||
      (filter === 'cancelled' && b.status === 'cancelled') ||
      (filter === 'confirmed' && b.status === 'confirmed');
    const matchSearch =
      !search ||
      b.guestName.toLowerCase().includes(search.toLowerCase()) ||
      b.id.toLowerCase().includes(search.toLowerCase()) ||
      b.guestEmail.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  return (
    <div className={styles.wrapper}>
      <div className={styles.toolbar}>
        <div className={styles.filters}>
          {['all','confirmed','cancelled','paid','unpaid'].map((f) => (
            <button
              key={f}
              className={`${styles.filterBtn} ${filter === f ? styles.active : ''}`}
              onClick={() => setFilter(f)}
              type="button"
            >
              {f.charAt(0).toUpperCase() + f.slice(1)}
            </button>
          ))}
        </div>
        <input
          className={styles.search}
          type="text"
          placeholder="Search name, email, ref code…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {filtered.length === 0 ? (
        <div className={styles.empty}>
          <span>🌸</span>
          <p>No bookings found.</p>
        </div>
      ) : (
        <div className={styles.tableWrap}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Ref Code</th>
                <th>Guest</th>
                <th>Room</th>
                <th>Check-in</th>
                <th>Check-out</th>
                <th>Nights</th>
                <th>Total</th>
                <th>Payment</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((b) => (
                <React.Fragment key={b.id}>
                  <tr
                    className={`${styles.row} ${b.status === 'cancelled' ? styles.rowCancelled : ''}`}
                    onClick={() => setExpandedId(expandedId === b.id ? null : b.id)}
                  >
                    <td><span className={styles.refCode}>{b.id}</span></td>
                    <td>
                      <div className={styles.guestName}>{b.guestName}</div>
                      <div className={styles.guestEmail}>{b.guestEmail}</div>
                    </td>
                    <td>
                      <span className={styles.roomTag}>
                        {b.room.icon} {b.room.name}
                      </span>
                    </td>
                    <td className={styles.date}>{formatDate(b.checkIn)}</td>
                    <td className={styles.date}>{formatDate(b.checkOut)}</td>
                    <td className={styles.center}>{b.nights}N</td>
                    <td className={styles.total}>₱{b.total.toLocaleString()}</td>
                    <td onClick={(e) => e.stopPropagation()}>
                      <button
                        className={`${styles.paidBtn} ${b.paid ? styles.paidYes : styles.paidNo}`}
                        onClick={() => onTogglePaid(b.id)}
                        type="button"
                        title="Click to toggle payment"
                      >
                        {b.paid ? '✓ Paid' : '✗ Unpaid'}
                      </button>
                    </td>
                    <td>
                      <span className={`${styles.statusBadge} ${STATUS_COLORS[b.status] || ''}`}>
                        {b.status}
                      </span>
                    </td>
                    <td onClick={(e) => e.stopPropagation()}>
                      {b.status !== 'cancelled' && (
                        <button
                          className={styles.cancelBtn}
                          onClick={() => onCancelBooking(b.id)}
                          type="button"
                        >
                          Cancel
                        </button>
                      )}
                    </td>
                  </tr>

                  {expandedId === b.id && (
                    <tr className={styles.expandedRow}>
                      <td colSpan={10}>
                        <div className={styles.expandedContent}>
                          <div className={styles.expandedItem}>
                            <span className={styles.expandLabel}>Guests</span>
                            <span>{b.guests} pax</span>
                          </div>
                          <div className={styles.expandedItem}>
                            <span className={styles.expandLabel}>Booked On</span>
                            <span>{new Date(b.createdAt).toLocaleString('en-PH')}</span>
                          </div>
                          <div className={styles.expandedItem}>
                            <span className={styles.expandLabel}>Special Requests</span>
                            <span>{b.specialRequests || <em>None</em>}</span>
                          </div>
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <div className={styles.tableFooter}>
        Showing {filtered.length} of {bookings.length} bookings
      </div>
    </div>
  );
};

export default BookingsTable;
